#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        if (n == 2) {
            printf("%d\n", 2 * m - 1);
        } else {
            printf("%d\n", m + (n - 2) * ((m + 1) / 2));
        }
    }
    return 0;
}

