import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            if (n == 2) {
                System.out.println(2 * m - 1);
            } else {
                System.out.println(m + (n - 2) * ((m + 1) / 2));
            }
        }
    }
}

